#include <stdio.h>

int main() {
    int n, m;
    scanf("%d %d", &n, &m);

    int a[n], b[m];

    // Read first array
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }

    // Read second array
    for (int i = 0; i < m; i++) {
        scanf("%d", &b[i]);
    }

    int mergedSize = n + m;
    int mergedArray[mergedSize];

    int i = 0, j = 0, k = 0;

    // Merge using two pointers
    while (i < n && j < m) {
        if (a[i] <= b[j]) {
            mergedArray[k++] = a[i++];
        } else {
            mergedArray[k++] = b[j++];
        }
    }

    // Copy remaining elements from a[]
    while (i < n) {
        mergedArray[k++] = a[i++];
    }

    // Copy remaining elements from b[]
    while (j < m) {
        mergedArray[k++] = b[j++];
    }

    // Print merged array
    for (int x = 0; x < mergedSize; x++) {
        printf("%d ", mergedArray[x]);
    }

    printf("\n");

    return 0;
}
